const amqp = require('amqplib');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = 'payment_events';

async function processPayment(paymentEvent) {
  console.log(`[x] Processing payment for transaction ID: ${paymentEvent.transactionId}`);
  console.log(`    Amount: ${paymentEvent.amount} ${paymentEvent.currency}`);
  console.log(`    User ID: ${paymentEvent.userId}`);
  console.log(`    Payment Method: ${paymentEvent.paymentMethod}`);

  // Simulate payment processing logic
  return new Promise(resolve => {
    setTimeout(() => {
      const success = Math.random() > 0.1; // 90% success rate for simulation
      if (success) {
        console.log(`[✓] Payment successful for transaction ID: ${paymentEvent.transactionId}`);
        resolve(true);
      } else {
        console.error(`[✗] Payment failed for transaction ID: ${paymentEvent.transactionId}`);
        resolve(false);
      }
    }, 2000); // Simulate a 2-second payment gateway call
  });
}

async function startConsumer() {
  let connection;
  try {
    connection = await amqp.connect(RABBITMQ_URL);
    console.log('Connected to RabbitMQ');

    const channel = await connection.createChannel();
    await channel.assertQueue(QUEUE_NAME, { durable: true });
    console.log(`Waiting for messages in queue: ${QUEUE_NAME}. To exit press CTRL+C`);

    channel.consume(QUEUE_NAME, async (msg) => {
      if (msg !== null) {
        try {
          const paymentEvent = JSON.parse(msg.content.toString());
          console.log(`[<-] Received payment event: ${JSON.stringify(paymentEvent)}`);

          const paymentSuccessful = await processPayment(paymentEvent);

          if (paymentSuccessful) {
            channel.ack(msg);
            console.log(`[->] Acknowledged message for transaction ID: ${paymentEvent.transactionId}`);
          } else {
            // For failed payments, you might want to NACK and requeue, or move to a dead-letter queue
            // For this example, we'll just NACK without requeueing to prevent endless loops on persistent failures
            channel.nack(msg, false, false); // requeue: false
            console.error(`[->] NACKed message for transaction ID: ${paymentEvent.transactionId} (not re-queued)`);
          }
        } catch (error) {
          console.error('Error processing message:', error);
          // NACK message if parsing or processing fails, potentially moving to a dead-letter queue
          channel.nack(msg, false, false); // requeue: false
        }
      }
    }, { noAck: false });

  } catch (error) {
    console.error('Failed to connect or consume from RabbitMQ:', error);
    if (connection) {
      try {
        await connection.close();
      } catch (closeError) {
        console.error('Error closing RabbitMQ connection:', closeError);
      }
    }
    // Implement a retry mechanism for production systems
    setTimeout(startConsumer, 5000); // Retry connection after 5 seconds
  }

  process.on('SIGINT', async () => {
    console.log('Shutting down consumer...');
    if (connection) {
      await connection.close();
    }
    process.exit(0);
  });
}

startConsumer();